insert into public.lore_entries (slug, title, category, content, pathway, epoch, city, npcs, sequences, tags, token_count)
values
  ('feysac-saint-millom', 'Feysac Empire — Saint Millom, the Imperial Capital', 'location', 'Saint Millom is the capital of the Feysac Empire, a great cold coastal city on the Midseashire shore — lesser than Backlund, Trier, or Feynapotter City, but the militarist north''s beating heart. It stands on the same ground where the Second Solomon Empire''s capital once rose, ringed by thick forests and the coal and iron mines that feed the empire''s foundries and guns, lashed by fierce North Sea winds and snowbound before October is out. At its centre is Aurmir Palace, the seat of the ruling Einhorn house, named — like so much in Feysac — for the Giant King Aurmir. Outside the walls looms the Great Twilight Hall, the Church of the God of Combat''s headquarters, raised in the likeness of the Giant King''s Court. The streets run to higher doorways and taller ceilings than a southerner expects, for this is a city where men claim the blood of giants, and where height itself is read as rank. To arrive in Saint Millom is to feel the whole weight of the warrior-north bearing down: disciplined, devout, and openly in love with strength.', null, 5, 'feysac', '{}', '{}', ARRAY['feysac-empire', 'saint-millom', 'midseashire', 'capital', 'geography'], 250),
  ('feysac-imperial-state', 'Feysac Empire — The Einhorn Throne & the Warrior-State', 'location', 'The Feysac Empire is ruled by the Einhorn family, an angel house of the Red Priest Pathway that holds the throne from Aurmir Palace and commands the Sonia Sea Fleet, the imperial navy. The Einhorns founded the realm after the Trunsoest Empire fell, splitting the weakened north with the backing of the God of Combat, whose Church has been the empire''s sole faith ever since — no other creed may preach here, and the Church itself polices every Beyonder incident. Status in Feysac is read first in height: the nobility and the military brass, claiming descent from giants through the Twilight Giant bloodline, routinely stand over two metres, and the brass are nobles or at least seasoned Beyonders. To Loen eyes the Feysacians are "northern barbarians" — boorish, hard-drinking (the Church itself sponsors the drink), their tongue the harsh Ancient Feysac. Beyond the walled towns and the internal Antares range lies a dangerous frontier of evil spirits and monsters that keeps every town''s militia drilled, while across the seas the empire holds colonies on Sonia Island, the Gargas Archipelago, and the Balams. Its coin is the gold hoorn.', null, 5, 'feysac', ARRAY['Awatoma Einhorn'], '{}', ARRAY['feysac-empire', 'einhorn', 'red-priest', 'militarism', 'geography'], 255),
  ('feynapotter-kingdom', 'The Feynapotter Kingdom', 'location', 'The Feynapotter Kingdom is the third-strongest nation of the Northern Continent, lying across the southern reaches below the Intis Republic and the Loen Kingdom, its capital at Feynapotter City. It is ruled by the Castiya family — an angel house of the Justiciar Pathway that founded the kingdom when the old empires fell — but its true character is set by its faith: this is the land of the Earth Mother, a romantic, matriarchal, devout realm that holds women in the highest regard, venerates the eldest grandmother, and treats marriage and childbearing as sacred. It is the continent''s breadbasket, its fertile fields and the Church''s blessed husbandry yielding such surplus that even Loen imports Feynapotter grain, and its people live longer and beg less than their northern neighbours. Once the kingdom shared its devotion with the Church of the God of Knowledge and Wisdom, until the two faiths fell to war and the Battle of the Violated Oath tore them apart — leaving the Earth Mother alone here, and three small states broken away. Its coin is the risot, its common tongue the Highlander descended from Ancient Feysac.', null, 5, 'feynapotter', '{}', '{}', ARRAY['feynapotter-kingdom', 'castiya', 'earth-mother', 'justiciar', 'geography'], 255),
  ('lenburg-knowledge-realm', 'Lenburg — Realm of the Knowledge-Faith', 'location', 'Lenburg is the foremost of the three small states that broke from the Feynapotter Kingdom at the Battle of the Violated Oath, and the strangest in its governance: it has no royal house at all. In its place the Church of the God of Knowledge and Wisdom rules in all but name, directing the country from the Holy Temple of Knowledge in the capital, Azshara — a temple that was once the god''s own earthly divine kingdom, left behind when he withdrew into the Astral World. Here knowledge is the highest good and "Omniscience means Omnipotence" the national creed: a Lenburger''s whole life is a ladder of examinations and evaluations, schooling compulsory down to the dead tongue of Ancient Feysac, talent and learning prized far above birth. The fashion runs to light-coloured clothes and brass ornaments, the god''s sacred metal; the coin is the gold sassen; the speech is a dialect of the Highlander shared with Feynapotter. To live in Lenburg is to be tested, ranked, and valued for what one knows.', null, 5, 'lenburg', '{}', '{}', ARRAY['lenburg', 'azshara', 'god-of-knowledge', 'geography', 'fifth-epoch'], 240),
  ('masin-knowledge-state', 'Masin — A Knowledge-Faith Splinter-State', 'location', 'Masin is one of the three small states that won their independence from the Feynapotter Kingdom at the Battle of the Violated Oath, set in the continent''s south below the Intis Republic and west toward the Fog Sea. Like its neighbours Lenburg and Segar, it carried off the worship of the God of Knowledge and Wisdom when it broke away, so that the patchwork of little realms along Feynapotter''s borders shares one faith between them where the kingdom they left keeps another. Masin is a quiet country of the southern marches, its coin the gold porter, its life ordered by the same reverence for learning that binds the Knowledge-faith states together. It is the kind of small, studious nation the great powers scarcely notice — until they need what its scholars know.', null, 5, 'masin', '{}', '{}', ARRAY['masin', 'god-of-knowledge', 'splinter-state', 'geography', 'fifth-epoch'], 180),
  ('segar-knowledge-state', 'Segar — A Knowledge-Faith Splinter-State', 'location', 'Segar is the easternmost of the three small states that split from the Feynapotter Kingdom at the Battle of the Violated Oath, set on the kingdom''s northeastern border. A single-faith nation like Lenburg and Masin, it keeps the worship of the God of Knowledge and Wisdom that all three carried out of Feynapotter, its life turned toward learning and the omniscient eye on the open book. From its marches come hard travellers of the southern seas — the treasure-hunter Anderson Hood, the Fog Sea''s strongest, was Segar-born before he made his name. Its coin is the gold złoty. Small and easily overlooked among the continent''s great nations, Segar is nonetheless a piece of the Knowledge-faith''s quiet dominion over the little realms that ring the Feynapotter Kingdom.', null, 5, 'segar', '{}', '{}', ARRAY['segar', 'god-of-knowledge', 'splinter-state', 'geography', 'fifth-epoch'], 185),
  ('combat-church-structure', 'Church of the God of Combat — Structure & Ranks', 'organization', 'Beneath its Chief Shepherd, the Church of the God of Combat is a martial hierarchy seated at the Great Twilight Hall outside Saint Millom — a hall raised in the likeness of the Giant King''s Court, by tradition the old residence of Giant King Aurmir himself. The Chief Shepherd Larrion commands the dioceses of the Feysac heartland and the colonies: Gargas (whose archbishop is but a Sequence 5 Guardian), Sonia Island, and West Balam, with the Holy Lake Cathedral at Raklev among its seats. Its clergy climb the Twilight Giant ladder rung by rung — Warrior, Pugilist, Weapon Master, Dawn Paladin, Guardian, Demon Hunter, Silver Knight, Glory — so that the "Warrior" and "Hunter" outsiders speak of are not separate paths but sequences of the one Twilight Giant Pathway the Church wields (the Death and Darkness paths it holds only in part). It keeps no separately named inquisition; its Beyonders themselves are its enforcers, and the policing of every Beyonder incident in the empire is the Church''s own charge. A brotherhood of men, height-proud and hard-drinking, it brooks no rival faith in Feysac and has feuded with the Church of the Evernight Goddess since its founding.', null, 5, 'feysac', ARRAY['Larrion'], '{}', ARRAY['god-of-combat', 'church', 'feysac', 'twilight-giant-pathway', 'structure', 'religion'], 255),
  ('npc-awatoma-einhorn', 'Awatoma Einhorn — Supreme Commander of the Feysac Navy', 'npc', 'Awatoma Einhorn is the Supreme Commander of the Feysac Navy, the angel-general the empire hails as "the Great Awatoma Einhorn, Ruler of the Fog of the Battlefield." He is of the imperial Einhorn house — the Red Priest line that holds the Feysac throne and the Sonia Sea Fleet — and a Weather Warlock, a Sequence 2 Angel who turns sea and storm against the empire''s enemies from the war-zone of the Sonia Sea. His kinsman Egor Einhorn serves as a commander beneath him; when Egor was once unmanned by a strange adventurer, it was Awatoma''s honorific name he called upon for aid. In a realm that measures a man by his height and his battles, Awatoma stands near the summit of both — the Einhorns'' war-leader and one of the deadliest servants of the militarist north.', null, 5, 'feysac', ARRAY['Awatoma Einhorn', 'Egor Einhorn'], ARRAY[2], ARRAY['feysac', 'einhorn', 'red-priest', 'navy', 'angel'], 200),
  ('npc-egor-einhorn', 'Egor Einhorn — Commander of the Feysac Imperial Navy', 'npc', 'Egor Einhorn is a commander of the Feysac Imperial Navy and a son of the imperial Einhorn house — a burly, bearded giant of a man over two metres tall who kept the flagship Nepos in the Sonia Sea war-zone. An Iron-blooded Knight, a Sequence 4 of the Red Priest Pathway, he is a hard and capable officer of the militarist north, kin and subordinate to the Supreme Commander Awatoma Einhorn. His one famous humiliation came when a lone adventurer aboard a captured ship — a man quietly digesting a potion he could not yet control — unnerved him so badly that Egor broke off and called on Awatoma''s name for protection. It is the kind of story Feysac''s height-proud officers never let a man forget.', null, 5, 'feysac', ARRAY['Egor Einhorn', 'Awatoma Einhorn', 'Klein Moretti'], ARRAY[4], ARRAY['feysac', 'einhorn', 'red-priest', 'navy'], 195),
  ('npc-ozil', 'Strongman Ozil — Combat-Faithful of the Underworld', 'npc', 'Ozil, called Strongman Ozil, was a Feysac-born son of the Church of the God of Combat and once a famous pirate of the seas before he sank into the Beyonder underworld of Bayam as the secret master of the Amyris Leaf Bar. A Pugilist — a Sequence 8 of the Twilight Giant Pathway — he carried the Combat faith''s raw ferocity into the shadows of the Rorsted Archipelago, an ally of the smuggler Mithor King. His end came at the hands of the bounty hunter Gehrman Sparrow, who killed him in early 1350 and saw his Beyonder characteristic sold on to the alchemist Cattleya — one more violent Feysac export the wider world quietly absorbed.', null, 5, 'bayam', ARRAY['Ozil', 'Mithor King', 'Klein Moretti', 'Cattleya'], ARRAY[8], ARRAY['feysac', 'god-of-combat', 'twilight-giant-pathway', 'bayam', 'pirate'], 175);
